import{_ as t,o as i,c as a,a3 as n}from"./chunks/framework.aYYe0dfI.js";const k=JSON.parse('{"title":"clore::net::detail::selecteventloop","description":"The function clore::net::detail::select_event_loop provides a single dispatch point for obtaining an active event loop reference. It first checks whether the incoming pointer loop is non‑null; if so, it dereferences and returns that loop directly. When loop is nullptr, the function falls back to kota::event_loop::current(), which must return a valid loop—this precondition is undefined if no event loop is active on the calling thread. The implementation thus relies on the runtime state of the kota::event_loop singleton and ensures the caller always receives a usable loop reference without further validation.","frontmatter":{"title":"clore::net::detail::selecteventloop","description":"The function clore::net::detail::select_event_loop provides a single dispatch point for obtaining an active event loop reference. It first checks whether the incoming pointer loop is non‑null; if so, it dereferences and returns that loop directly. When loop is nullptr, the function falls back to kota::event_loop::current(), which must return a valid loop—this precondition is undefined if no event loop is active on the calling thread. The implementation thus relies on the runtime state of the kota::event_loop singleton and ensures the caller always receives a usable loop reference without further validation.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/client/functions/select-event-loop.md","filePath":"en/clore/modules/client/functions/select-event-loop.md"}'),s={name:"clore/modules/client/functions/select-event-loop.md"};function l(o,e,r,c,p,h){return i(),a("div",null,[...e[0]||(e[0]=[n("",16)])])}const u=t(s,[["render",l]]);export{k as __pageData,u as default};
